try {
  // 1. 安全获取 AccessToken
  // 请确保这里 $('节点名称') 里的名称和您流程图里完全一致
  const tokenNode = $('微信AccessToken').first();
  const accessToken = tokenNode ? (tokenNode.json.body.access_token || tokenNode.json.access_token) : null;

  if (!accessToken) {
    console.log("⚠️ 警告: 未找到 AccessToken，请检查节点引用名称");
  }

  // 2. 提取所有订单号 (flatMap 自动展平数组)
  // 微信接口通常返回字段是 order_id_list，如果是其他名字(如 orders)请在这里修改
  const allOrderIds = $input.all().flatMap(item => {
    return item.json.order_id_list || item.json.orders || [];
  });

  // 3. 去重 (防止重复抓取)
  const uniqueIds = [...new Set(allOrderIds)];

  // 4. 【核心逻辑】构建返回数据
  if (uniqueIds.length > 0) {
    //情况 A: 有订单，正常返回，is_empty = false
    return uniqueIds.map(orderId => ({
      json: {
        order_id: orderId,         // 订单号
        access_token: accessToken, // 透传 Token
        is_empty: false            // 标记：这是有效数据
      }
    }));
  } else {
    // 情况 B: 没订单，返回一个“伪造包”保活，is_empty = true
    // 这样 n8n 就会认为“节点执行成功”，继续往下走，不会卡死循环
    return [{
      json: {
        order_id: null,
        is_empty: true // 标记：这是空数据，后面要过滤掉
      }
    }];
  }

} catch (error) {
  console.error('节点执行错误:', error);
  // 出错也返回一个伪造包，防止整个任务挂掉
  return [{ json: { is_empty: true, error: error.message } }];
}

try {
// 从Set节点获取总时间戳
const totalStartTs = $node["微信AccessToken"].json["start_ts"];
const totalEndTs = $node["微信AccessToken"].json["end_ts"];
const accesstoken = $input.first().json.body.access_token
// 7天对应的秒数：7*24*60*60 = 604800
const sevenDaysInSeconds = 60 * 60 * 24;

// 存储拆分后的所有区间
const timeRanges = [];

// 循环拆分时间区间
let currentStartTs = totalStartTs;
while (currentStartTs < totalEndTs) {
    // 计算当前区间的结束时间（最多7天，不超过总结束时间）
    let currentEndTs = currentStartTs + sevenDaysInSeconds - 1; // 减1避免重复（比如0点到下一个0点前1秒）
    if (currentEndTs > totalEndTs) {
        currentEndTs = totalEndTs;
    }

    // 转换为可读时间（可选，方便调试）
    const formatDate = (ts) => new Date(ts * 1000).toLocaleString('zh-CN');

    // 添加当前区间到数组
    timeRanges.push({
        start_timestamp: currentStartTs,
        end_timestamp: currentEndTs,
        start_time: formatDate(currentStartTs),
        end_time: formatDate(currentEndTs),
        accesstoken
    });

    // 移动到下一个区间（开始时间=当前结束时间+1）
    currentStartTs = currentEndTs + 1;
}

// 返回所有拆分后的区间（供后续节点调用）
return timeRanges

} catch (error) {
  console.error('节点执行错误:', error);
  return [{ json: { _error: true, message: error.message || String(error), node: '时间段拆分-天' } }];
}

