function formatTs(ts) {
  if (ts && (typeof ts === 'number' || typeof ts === 'string')) {
    const tsNum = typeof ts === 'string' ? parseInt(ts) : ts;
    if (tsNum > 0) {
      const date = new Date(tsNum * 1000);
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const day = String(date.getDate()).padStart(2, '0');
      const hours = String(date.getHours()).padStart(2, '0');
      const minutes = String(date.getMinutes()).padStart(2, '0');
      const seconds = String(date.getSeconds()).padStart(2, '0');
      return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;
    }
  }
  return '';
}

function formatPrice(cents) {
  if (cents && (typeof cents === 'number' || typeof cents === 'string')) {
    const num = typeof cents === 'string' ? parseFloat(cents) : cents;
    return Math.round(num / 100 * 100) / 100;
  }
  return 0.0;
}

function getEnumDesc(enumMap, value, defaultVal = '') {
  if (value === null || value === undefined) return defaultVal;
  return enumMap[value] !== undefined ? enumMap[value] : `${defaultVal}(${value})`;
}

function safeGet(data, keys, defaultVal = '') {
  let current = data;
  for (const key of keys) {
    if (current && typeof current === 'object' && key in current) {
      current = current[key];
    } else {
      return defaultVal;
    }
  }
  return current;
}

